var surah024 = {
  number: 24,
  nameArabic: "an-Nur",
  nameEnglish: "An-Nur",
  meaning: "The Light",
  totalAyahs: 64,
  ayahs: [
    { number: 1, arabic: "سُورَةٌ أَنزَلْنَٰهَا وَفَرَضْنَٰهَا وَأَنزَلْنَا فِيهَآ ءَايَٰتٍۭ بَيِّنَٰتٍۢ لَّعَلَّكُمْ تَذَكَّرُونَ", transliteration: "Sooratun anzalnaha wafaradnaha waanzalna feeha ayatin bayyinatin laAAallakum tathakkaroona", transliterationB: "Sooratun anzalnaahaa wa faradnaahaa wa anzalnaa feehaaa Aayaatim baiyinaatil la'allakum tazakkaroon", english: "A sura which We have sent down and which We have ordained in it have We sent down Clear Signs, in order that ye may receive admonition", romanUrdu: "Yeh ek surat hai jisko humne nazil kiya hai, aur isey humne farz kiya hai, aur is mein humne saaf saaf hidayaat nazil ki hain, shayad ke tum sabaq lo" },
    { number: 2, arabic: "ٱلزَّانِيَةُ وَٱلزَّانِى فَٱجْلِدُوا۟ كُلَّ وَٰحِدٍۢ مِّنْهُمَا مِا۟ئَةَ جَلْدَةٍۢ ۖ وَلَا تَأْخُذْكُم بِهِمَا رَأْفَةٌۭ فِى دِينِ ٱللَّهِ إِن كُنتُمْ تُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۖ وَلْيَشْهَدْ عَذَابَهُمَا طَآئِفَةٌۭ مِّنَ ٱلْمُؤْمِنِينَ", transliteration: "Alzzaniyatu waalzzanee faijlidoo kulla wahidin minhuma miata jaldatin wala takhuthkum bihima rafatun fee deeni Allahi in kuntum tuminoona biAllahi waalyawmi alakhiri walyashhad AAathabahuma taifatun mina almumineena", transliterationB: "Azzaaniyatu wazzaanee fajlidoo kulla waahidim minhumaa mi'ata jaldatinw wa laa taakhuzkum bihimaa raafatun fee deenil laahi in kuntum tu'minoona billaahi wal Yawmil Aakhiri wal yashhad 'azaabahumaa taaa'ifatum minal mu'mineen", english: "The woman and the man guilty of adultery or fornication,- flog each of them with a hundred stripes: Let not compassion move you in their case, in a matter prescribed by Allah, if ye believe in Allah and the Last Day: and let a party of the Believers witness their punishment", romanUrdu: "Zaniya (adulterous) aurat zaani mard, dono mein se har ek ko sau (hundred) kodey (lashes) maaro aur inpar tars khane ka jazba Allah ke deen ke maamle mein tumko daamangeer (pity) na ho agar tum Allah taala aur roz-e-aakhir par iman rakhte ho, aur inko saza detay waqt ehle iman ka ek giroh moujood rahey" },
    { number: 3, arabic: "ٱلزَّانِى لَا يَنكِحُ إِلَّا زَانِيَةً أَوْ مُشْرِكَةًۭ وَٱلزَّانِيَةُ لَا يَنكِحُهَآ إِلَّا زَانٍ أَوْ مُشْرِكٌۭ ۚ وَحُرِّمَ ذَٰلِكَ عَلَى ٱلْمُؤْمِنِينَ", transliteration: "Alzzanee la yankihu illa zaniyatan aw mushrikatan waalzzaniyatu la yankihuha illa zanin aw mushrikun wahurrima thalika AAala almumineena", transliterationB: "Azzaanee laa yankihu illaa zaaniyatan aw mushrikatanw wazzaaniyatu laa yankihuhaaa illaa zaanin aw mushrik; wa hurrima zaalika 'alal mu'mineen", english: "Let no man guilty of adultery or fornication marry and but a woman similarly guilty, or an Unbeliever: nor let any but such a man or an Unbeliever marry such a woman: to the Believers such a thing is forbidden", romanUrdu: "Zaani (man guilty of adultery) nikah na karey magar zaniya ke saath ya mushrika ke saath, aur zaniya ke saath nikah na karey magar zaani ya mushrik. Aur yeh haraam kardiya gaya hai ehle iman par" },
    { number: 4, arabic: "وَٱلَّذِينَ يَرْمُونَ ٱلْمُحْصَنَٰتِ ثُمَّ لَمْ يَأْتُوا۟ بِأَرْبَعَةِ شُهَدَآءَ فَٱجْلِدُوهُمْ ثَمَٰنِينَ جَلْدَةًۭ وَلَا تَقْبَلُوا۟ لَهُمْ شَهَٰدَةً أَبَدًۭا ۚ وَأُو۟لَٰٓئِكَ هُمُ ٱلْفَٰسِقُونَ", transliteration: "Waallatheena yarmoona almuhsanati thumma lam yatoo biarbaAAati shuhadaa faijlidoohum thamaneena jaldatan wala taqbaloo lahum shahadatan abadan waolaika humu alfasiqoona", transliterationB: "Wallazeena yarmoonal muhsanaati summa lam yaatoo bi-arba'ati shuhadaaa'a fajlidoohum samaaneena jaldatanw wa laa taqbaloo lahum shahaadatan abadaa; wa ulaaa'ika humul faasiqoon", english: "And those who launch a charge against chaste women, and produce not four witnesses (to support their allegations),- flog them with eighty stripes; and reject their evidence ever after: for such men are wicked transgressors", romanUrdu: "Aur jo log paak daaman auraton par tohmat (ilzam /bohtan/slander) lagayein, phir char (four) gawaah lekar na aayein, unko assi (eighty) kodey (lashes) maaro , aur unki shahadat kabhi qabool na karo. Aur woh khud hi faasiq hain" },
    { number: 5, arabic: "إِلَّا ٱلَّذِينَ تَابُوا۟ مِنۢ بَعْدِ ذَٰلِكَ وَأَصْلَحُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Illa allatheena taboo min baAAdi thalika waaslahoo fainna Allaha ghafoorun raheemun", transliterationB: "Illal lazeena taaboo mim ba'di zaalika wa aslahoo fa innal laaha Ghafoorur Raheem", english: "Unless they repent thereafter and mend (their conduct); for Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Siwaye un logon ke jo is harakat ke baad taaib (repent) ho jayein aur islaah karlein ke Allah zaroor (unke haqq mein) gafoor o raheem hai" },
    { number: 6, arabic: "وَٱلَّذِينَ يَرْمُونَ أَزْوَٰجَهُمْ وَلَمْ يَكُن لَّهُمْ شُهَدَآءُ إِلَّآ أَنفُسُهُمْ فَشَهَٰدَةُ أَحَدِهِمْ أَرْبَعُ شَهَٰدَٰتٍۭ بِٱللَّهِ ۙ إِنَّهُۥ لَمِنَ ٱلصَّٰدِقِينَ", transliteration: "Waallatheena yarmoona azwajahum walam yakun lahum shuhadao illa anfusuhum fashahadatu ahadihim arbaAAu shahadatin biAllahi innahu lamina alssadiqeena", transliterationB: "Wallazeena yarmoona azwaajahum wa lam yakul lahum shuhadaaa'u illaaa anfusuhum fashahaadatu ahadihim arb'u shahaadaatim billaahi innahoo laminas saadiqeen", english: "And for those who launch a charge against their spouses, and have (in support) no evidence but their own,- their solitary evidence (can be received) if they bear witness four times (with an oath) by Allah that they are solemnly telling the truth", romanUrdu: "Aur jo log apni biwiyon par ilzam lagayein aur unke paas khud unke apne siwa doosre koi gawaah na hon to unmein se ek shaks ki shahadat(yeh hai ke woh) char martaba Allah ki kasam kha kar gawahi dey ke woh (apne ilzam mein) saccha hai" },
    { number: 7, arabic: "وَٱلْخَٰمِسَةُ أَنَّ لَعْنَتَ ٱللَّهِ عَلَيْهِ إِن كَانَ مِنَ ٱلْكَٰذِبِينَ", transliteration: "Waalkhamisatu anna laAAnata Allahi AAalayhi in kana mina alkathibeena", transliterationB: "Wal khaamisatu anna la'natal laahi 'alaihi in kaana minal kaazibeen", english: "And the fifth (oath) (should be) that they solemnly invoke the curse of Allah on themselves if they tell a lie", romanUrdu: "Aur panchwi (fifth) baar kahey ke uspar Allah ki lanat ho agar woh (apne ilzaam mein) jhoota ho" },
    { number: 8, arabic: "وَيَدْرَؤُا۟ عَنْهَا ٱلْعَذَابَ أَن تَشْهَدَ أَرْبَعَ شَهَٰدَٰتٍۭ بِٱللَّهِ ۙ إِنَّهُۥ لَمِنَ ٱلْكَٰذِبِينَ", transliteration: "Wayadrao AAanha alAAathaba an tashhada arbaAAa shahadatin biAllahi innahu lamina alkathibeena", transliterationB: "Wa yadra'u anhal 'azaaba an tashhada arba'a shahaa daatim billaahi innahoo laminal kaazibeen", english: "But it would avert the punishment from the wife, if she bears witness four times (with an oath) By Allah, that (her husband) is telling a lie", romanUrdu: "Aur aurat se saza is tarah tal sakti hai ke woh char martaba Allah ki kasam kha kar shahadat dey ke yeh shaks (apne ilzam mein) jhoota hai" },
    { number: 9, arabic: "وَٱلْخَٰمِسَةَ أَنَّ غَضَبَ ٱللَّهِ عَلَيْهَآ إِن كَانَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Waalkhamisata anna ghadaba Allahi AAalayha in kana mina alssadiqeena", transliterationB: "Wal khaamisata anna ghadabal laahi 'alaihaaa in kaana minas saadiqeen", english: "And the fifth (oath) should be that she solemnly invokes the wrath of Allah on herself if (her accuser) is telling the truth", romanUrdu: "Aur panchwi martaba kahey ke us bandi par Allah ka gazab totay agar woh (apne ilzam mein) saccha ho" },
    { number: 10, arabic: "وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ وَأَنَّ ٱللَّهَ تَوَّابٌ حَكِيمٌ", transliteration: "Walawla fadlu Allahi AAalaykum warahmatuhu waanna Allaha tawwabun hakeemun", transliterationB: "Wa law laa fadlul laahi 'alaikum wa rahmatuhoo wa annal laaha Tawwaabun Hakeem", english: "If it were not for Allah's grace and mercy on you, and that Allah is Oft-Returning, full of Wisdom,- (Ye would be ruined indeed)", romanUrdu: "Tum logon par Allah ka fazl aur uska reham na hota aur yeh baat na hoti ke Allah bada iltifaat (most forgiving) farmane wala aur hakeem hai, to (biwiyon par ilzam ka maamla tumhein badi pechidgi mein daal deta)" },
    { number: 11, arabic: "إِنَّ ٱلَّذِينَ جَآءُو بِٱلْإِفْكِ عُصْبَةٌۭ مِّنكُمْ ۚ لَا تَحْسَبُوهُ شَرًّۭا لَّكُم ۖ بَلْ هُوَ خَيْرٌۭ لَّكُمْ ۚ لِكُلِّ ٱمْرِئٍۢ مِّنْهُم مَّا ٱكْتَسَبَ مِنَ ٱلْإِثْمِ ۚ وَٱلَّذِى تَوَلَّىٰ كِبْرَهُۥ مِنْهُمْ لَهُۥ عَذَابٌ عَظِيمٌۭ", transliteration: "Inna allatheena jaoo bialifki AAusbatun minkum la tahsaboohu sharran lakum bal huwa khayrun lakum likulli imriin minhum ma iktasaba mina alithmi waallathee tawalla kibrahu minhum lahu AAathabun AAatheemun", transliterationB: "Innal lazeena jaaa'oo bilifki 'usbatum minkum; laa tahsaboohu sharral lakum bal huwa khairul lakum; likul limri'im minhum mak tasaba minal-ism; wallazee tawallaa kibrahoo minhum lahoo 'azaabun 'azeem", english: "Those who brought forward the lie are a body among yourselves: think it not to be an evil to you; On the contrary it is good for you: to every man among them (will come the punishment) of the sin that he earned, and to him who took on himself the lead among them, will be a penalty grievous", romanUrdu: "Jo log yeh bohtan (slander) ghadh laye hain woh tumhare hi andar ka ek tola hain. Is waqiye ko apne haqq mein sharr na samajho balke yeh bhi tumhare liye khair hi hai. Jisne is mein jitna hissa liya usne utna hi gunaah sametha aur jis shaks ne iski zimmedari ka bada hissa apne sar liya uske liye to azaab e azeem hai" },
    { number: 12, arabic: "لَّوْلَآ إِذْ سَمِعْتُمُوهُ ظَنَّ ٱلْمُؤْمِنُونَ وَٱلْمُؤْمِنَٰتُ بِأَنفُسِهِمْ خَيْرًۭا وَقَالُوا۟ هَٰذَآ إِفْكٌۭ مُّبِينٌۭ", transliteration: "Lawla ith samiAAtumoohu thanna almuminoona waalmuminatu bianfusihim khayran waqaloo hatha ifkun mubeenun", transliterationB: "Law laaa iz sami'tumoohu zannal mu'minoona walmu'minaatu bi anfusihim khairanw wa qaaloo haazaaa ifkum mmubeen", english: "Why did not the believers - men and women - when ye heard of the affair,- put the best construction on it in their own minds and say, \"This (charge) is an obvious lie", romanUrdu: "Jis waqt tum logon ne isey suna tha usi waqt kyun na momin mardon aur momin auraton ne apne aap se neik gumaan kiya aur kyun na kehdiya ke yeh sareeh bohtan (slander) hai" },
    { number: 13, arabic: "لَّوْلَا جَآءُو عَلَيْهِ بِأَرْبَعَةِ شُهَدَآءَ ۚ فَإِذْ لَمْ يَأْتُوا۟ بِٱلشُّهَدَآءِ فَأُو۟لَٰٓئِكَ عِندَ ٱللَّهِ هُمُ ٱلْكَٰذِبُونَ", transliteration: "Lawla jaoo AAalayhi biarbaAAati shuhadaa faith lam yatoo bialshshuhadai faolaika AAinda Allahi humu alkathiboona", transliterationB: "Law laa jaaa'oo 'alaihi bi-arba'ati shuhadaaa'; fa iz lam yaatoo bishshuhadaaa'i fa ulaaa 'ika 'indal laahi humul kaaziboon", english: "Why did they not bring four witnesses to prove it? When they have not brought the witnesses, such men, in the sight of Allah, (stand forth) themselves as liars", romanUrdu: "Woh log (apne ilzam ke saboot mein) char gawah kyun na laye? Ab ke woh gawah nahin laye hain, Allah ke nazdeek wahi jhootey hain" },
    { number: 14, arabic: "وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ لَمَسَّكُمْ فِى مَآ أَفَضْتُمْ فِيهِ عَذَابٌ عَظِيمٌ", transliteration: "Walawla fadlu Allahi AAalaykum warahmatuhu fee alddunya waalakhirati lamassakum fee ma afadtum feehi AAathabun AAatheemun", transliterationB: "Wa law laa fadlul laahi 'alaikum wa rahmatuhoo fiddunyaa wal aakhirati lamassakum fee maaa afadtum feehi 'azaabun 'azeem", english: "Were it not for the grace and mercy of Allah on you, in this world and the Hereafter, a grievous penalty would have seized you in that ye rushed glibly into this affair", romanUrdu: "Agar tum logon par duniya aur aakhirat mein Allah ka fazal aur reham o karam na hota to jin baaton mein tum padh gaye thay unki padash mein bada azaab tumhein aa leta" },
    { number: 15, arabic: "إِذْ تَلَقَّوْنَهُۥ بِأَلْسِنَتِكُمْ وَتَقُولُونَ بِأَفْوَاهِكُم مَّا لَيْسَ لَكُم بِهِۦ عِلْمٌۭ وَتَحْسَبُونَهُۥ هَيِّنًۭا وَهُوَ عِندَ ٱللَّهِ عَظِيمٌۭ", transliteration: "Ith talaqqawnahu bialsinatikum wataqooloona biafwahikum ma laysa lakum bihi AAilmun watahsaboonahu hayyinan wahuwa AAinda Allahi AAatheemun", transliterationB: "iz talaqqawnahoo bi alsinatikum wa taqooloona bi afwaahikum maa laisa lakum bihee 'ilmunw wa tahsaboo nahoo haiyinanw wa huwa 'indl laahi 'azeem", english: "Behold, ye received it on your tongues, and said out of your mouths things of which ye had no knowledge; and ye thought it to be a light matter, while it was most serious in the sight of Allah", romanUrdu: "(Zara gaur to karo, us waqt tum kaisi sakht galati kar rahey thay) jabke tumhari ek zubaan se dusri zubaan is jhoot ko leti chali jaa rahi thi aur tum apne mooh se woh kuch kahey jaa rahey thay jiske mutaalik tumhein koi ilm na tha. Tum isey ek mamuli baat samajh rahey thay, halanke Allah ke nazdeek yeh badi baat thi" },
    { number: 16, arabic: "وَلَوْلَآ إِذْ سَمِعْتُمُوهُ قُلْتُم مَّا يَكُونُ لَنَآ أَن نَّتَكَلَّمَ بِهَٰذَا سُبْحَٰنَكَ هَٰذَا بُهْتَٰنٌ عَظِيمٌۭ", transliteration: "Walawla ith samiAAtumoohu qultum ma yakoonu lana an natakallama bihatha subhanaka hatha buhtanun AAatheemun", transliterationB: "Wa law laaa iz sami'tu moohu qultum maa yakoonu lanaaa an natakallama bihaazaa Subhaanaka haaza buhtaanun 'azeem", english: "And why did ye not, when ye heard it, say? - \"It is not right of us to speak of this: Glory to Allah! this is a most serious slander", romanUrdu: "Kyun na usey sunte hi tumne kehdiya “humein aisi baat zubaan se nikalna zeib nahin deta, Subhan Allah , yeh to ek bohtan e azeem hai”" },
    { number: 17, arabic: "يَعِظُكُمُ ٱللَّهُ أَن تَعُودُوا۟ لِمِثْلِهِۦٓ أَبَدًا إِن كُنتُم مُّؤْمِنِينَ", transliteration: "YaAAithukumu Allahu an taAAoodoo limithlihi abadan in kuntum mumineena", transliterationB: "Ya'izukumul laahu an ta'oodoo limisliheee abadan in kuntum mu'mineen", english: "Allah doth admonish you, that ye may never repeat such (conduct), if ye are (true) Believers", romanUrdu: "Allah tumko naseehat karta hai ke aainda kabhi aisi harakat na karna agar tum momin ho" },
    { number: 18, arabic: "وَيُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ ۚ وَٱللَّهُ عَلِيمٌ حَكِيمٌ", transliteration: "Wayubayyinu Allahu lakumu alayati waAllahu AAaleemun hakeemun", transliterationB: "Wa yubaiyinul laahu lakumul Aayaat; wallaahu 'Aleemun Hakeem", english: "And Allah makes the Signs plain to you: for Allah is full of knowledge and wisdom", romanUrdu: "Allah tumhein saaf saaf hidayaat deta hai aur woh aleem o hakeem hai" },
    { number: 19, arabic: "إِنَّ ٱلَّذِينَ يُحِبُّونَ أَن تَشِيعَ ٱلْفَٰحِشَةُ فِى ٱلَّذِينَ ءَامَنُوا۟ لَهُمْ عَذَابٌ أَلِيمٌۭ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ ۚ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", transliteration: "Inna allatheena yuhibboona an tasheeAAa alfahishatu fee allatheena amanoo lahum AAathabun aleemun fee alddunya waalakhirati waAllahu yaAAlamu waantum la taAAlamoona", transliterationB: "Innal lazeena yuhibboona an tashee'al faahishatu fil lazeena aamanoo lahum 'azaabun aleemun fid dunyaa wal Aakhirah; wallaahu ya'lamu wa antum laa ta'lamoon", english: "Those who love (to see) scandal published broadcast among the Believers, will have a grievous Penalty in this life and in the Hereafter: Allah knows, and ye know not", romanUrdu: "Jo log chahte hain ke iman laney walon ke giroh mein fahash (indecency) phayle woh duniya aur aakhirat mein dardnaak saza ke musthaq hain. Allah jaanta hai aur tum nahin jaante" },
    { number: 20, arabic: "وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ وَأَنَّ ٱللَّهَ رَءُوفٌۭ رَّحِيمٌۭ", transliteration: "Walawla fadlu Allahi AAalaykum warahmatuhu waanna Allaha raoofun raheemun", transliterationB: "Wa law laa fadlul laahi 'alaikum wa rahmatuhoo wa annal laaha Ra'oofur Raheem", english: "Were it not for the grace and mercy of Allah on you, and that Allah is full of kindness and mercy, (ye would be ruined indeed)", romanUrdu: "Agar Allah ka fazal aur uska reham o karam tumpar na hota aur yeh baat na hoti ke Allah bada shafeeq o raheem hai (to yeh cheez jo abhi tumhare andar phailayi gayi thi badtareen nataij dikha deti)" },
    { number: 21, arabic: "۞ يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَٰنِ ۚ وَمَن يَتَّبِعْ خُطُوَٰتِ ٱلشَّيْطَٰنِ فَإِنَّهُۥ يَأْمُرُ بِٱلْفَحْشَآءِ وَٱلْمُنكَرِ ۚ وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ مَا زَكَىٰ مِنكُم مِّنْ أَحَدٍ أَبَدًۭا وَلَٰكِنَّ ٱللَّهَ يُزَكِّى مَن يَشَآءُ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌۭ", transliteration: "Ya ayyuha allatheena amanoo la tattabiAAoo khutuwati alshshaytani waman yattabiAA khutuwati alshshaytani fainnahu yamuru bialfahshai waalmunkari walawla fadlu Allahi AAalaykum warahmatuhu ma zaka minkum min ahadin abadan walakinna Allaha yuzakkee man yashao waAllahu sameeAAun AAaleemun", transliterationB: "Yaaa aiyuhal lazeena aamanoo laa tattabi'oo khutuwaatish Shaitaan; wa many-yattabi' khutuwaatish Shaitaani fa innahoo yaamuru bilfahshaaa'i walmunkar; wa law laa fadlul laahi 'alaikum wa rahmatuhoo maa zakaa minkum min ahadin abadanw wa laakinnal laaha yuzakkee many-yashaaa'; wallaahu Samee'un 'Aleem", english: "O ye who believe! follow not Satan's footsteps: if any will follow the footsteps of Satan, he will (but) command what is shameful and wrong: and were it not for the grace and mercy of Allah on you, not one of you would ever have been pure: but Allah doth purify whom He pleases: and Allah is One Who hears and knows (all things)", romanUrdu: "Aey logon jo iman laye ho, shaytan ke nakshe qadam par na chalo, uski pairwi (jo) koi karega to woh usey fahash (indecency) aur badi (wickedness) hi ka hukum dega.Agar Allah ka fazal aur uska reham o karam tumpar na hota to tum mein se koi shaks paak na ho sakta, magar Allah hi jisey chahta hai paak kardeta hai, aur Allah sunnay wala aur jaanney wala hai" },
    { number: 22, arabic: "وَلَا يَأْتَلِ أُو۟لُوا۟ ٱلْفَضْلِ مِنكُمْ وَٱلسَّعَةِ أَن يُؤْتُوٓا۟ أُو۟لِى ٱلْقُرْبَىٰ وَٱلْمَسَٰكِينَ وَٱلْمُهَٰجِرِينَ فِى سَبِيلِ ٱللَّهِ ۖ وَلْيَعْفُوا۟ وَلْيَصْفَحُوٓا۟ ۗ أَلَا تُحِبُّونَ أَن يَغْفِرَ ٱللَّهُ لَكُمْ ۗ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌ", transliteration: "Wala yatali oloo alfadli minkum waalssaAAati an yutoo olee alqurba waalmasakeena waalmuhajireena fee sabeeli Allahi walyaAAfoo walyasfahoo ala tuhibboona an yaghfira Allahu lakum waAllahu ghafoorun raheemun", transliterationB: "Wa laa yaatali ulul fadli minkum wassa'ati ai yu'tooo ulil qurbaa walmasaakeena walmuhaajireena fee sabeelillaahi walya'foo walyasfahoo; alaa tuhibboona ai yaghfiral laahu lakum; wal laahu Ghafoorur Raheem", english: "Let not those among you who are endued with grace and amplitude of means resolve by oath against helping their kinsmen, those in want, and those who have left their homes in Allah's cause: let them forgive and overlook, do you not wish that Allah should forgive you? For Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Tum mein se jo log saahib e fazal (bountiful) aur saahib e maqdarat (means) hain woh is baat ki kasam na kha baithein ke apne rishtedar, miskeen aur muhajir-fi-sabeelillah (who have left their homes for the cause of Allah) logon ki madad na karenge. Unhein maaf kardena chahiye aur darguazar karna chahiye. Kya tum nahin chahte ke Allah tumhein maaf karey? Aur Allah ki siffat yeh hai ke woh gafoor aur raheem hai" },
    { number: 23, arabic: "إِنَّ ٱلَّذِينَ يَرْمُونَ ٱلْمُحْصَنَٰتِ ٱلْغَٰفِلَٰتِ ٱلْمُؤْمِنَٰتِ لُعِنُوا۟ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَلَهُمْ عَذَابٌ عَظِيمٌۭ", transliteration: "Inna allatheena yarmoona almuhsanati alghafilati almuminati luAAinoo fee alddunya waalakhirati walahum AAathabun AAatheemun", transliterationB: "Innal lazeena yarmoonal muhsanaatil ghaafilaatil mu'minaati lu'inoo fid dunyaa wal Aakhirati wa lahum 'azaabun 'azeem", english: "Those who slander chaste women, indiscreet but believing, are cursed in this life and in the Hereafter: for them is a grievous Penalty", romanUrdu: "Jo log paak daaman, be-khabar, momin auraton par tohmatein (slandering) lagate hain unpar duniya aur aakhirat mein laanat ki gayi aur unke liye bada azaab hai" },
    { number: 24, arabic: "يَوْمَ تَشْهَدُ عَلَيْهِمْ أَلْسِنَتُهُمْ وَأَيْدِيهِمْ وَأَرْجُلُهُم بِمَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Yawma tashhadu AAalayhim alsinatuhum waaydeehim waarjuluhum bima kanoo yaAAmaloona", transliterationB: "Yawma tashhhadu 'alaihim alsinatuhum wa aideehim wa arjuluhum bimaa kaanoo ya'maloon", english: "On the Day when their tongues, their hands, and their feet will bear witness against them as to their actions", romanUrdu: "Woh us din ko bhool na jayein jabke unki apni zubaanein aur unke apne haath paon unke kartooton ki gawahi dengey" },
    { number: 25, arabic: "يَوْمَئِذٍۢ يُوَفِّيهِمُ ٱللَّهُ دِينَهُمُ ٱلْحَقَّ وَيَعْلَمُونَ أَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ ٱلْمُبِينُ", transliteration: "Yawmaithin yuwaffeehimu Allahu deenahumu alhaqqa wayaAAlamoona anna Allaha huwa alhaqqu almubeenu", transliterationB: "Yawma'iziny yuwaf feehimul laahu deenahumul haqqa wa ya'lamoona annal laaha Huwal Haqqul Mubeen", english: "On that Day Allah will pay them back (all) their just dues, and they will realise that Allah is the (very) Truth, that makes all things manifest", romanUrdu: "Us din Allah woh badla unhein bharpur de dega jiske woh mustahiq hain aur unhein maloom ho jayega ke Allah hi haqq hai. Sach ko sach kar dikhane wala" },
    { number: 26, arabic: "ٱلْخَبِيثَٰتُ لِلْخَبِيثِينَ وَٱلْخَبِيثُونَ لِلْخَبِيثَٰتِ ۖ وَٱلطَّيِّبَٰتُ لِلطَّيِّبِينَ وَٱلطَّيِّبُونَ لِلطَّيِّبَٰتِ ۚ أُو۟لَٰٓئِكَ مُبَرَّءُونَ مِمَّا يَقُولُونَ ۖ لَهُم مَّغْفِرَةٌۭ وَرِزْقٌۭ كَرِيمٌۭ", transliteration: "Alkhabeethatu lilkhabeetheena waalkhabeethoona lilkhabeethati waalttayyibatu lilttayyibeena waalttayyiboona lilttayyibati olaika mubarraoona mimma yaqooloona lahum maghfiratun warizqun kareemun", transliterationB: "Alkhabeesaatu lilkha beeseena walkhabeesoona lilkhabeesaati wattaiyibaatu littaiyibeena wattaiyiboona littaiyibaat; ulaaa'ika mubar ra'oona maimma yaqooloona lahum maghfiratunw wa rizqun kareem", english: "Women impure are for men impure, and men impure for women impure and women of purity are for men of purity, and men of purity are for women of purity: these are not affected by what people say: for them there is forgiveness, and a provision honourable", romanUrdu: "Khabees (Impure) auratein khabees mardon ke liye hain aur khabees (Impure) mard khabees (Impure) auraton ke liye. Paakeeza auratein pakeeza mardon ke liya hain aur pakeeza mard pakeeza auraton ke liye. Unka daaman paak hai un baaton se jo banane waley banate hain. Unke liye magfirat hai aur rizq e kareem" },
    { number: 27, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَدْخُلُوا۟ بُيُوتًا غَيْرَ بُيُوتِكُمْ حَتَّىٰ تَسْتَأْنِسُوا۟ وَتُسَلِّمُوا۟ عَلَىٰٓ أَهْلِهَا ۚ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ لَعَلَّكُمْ تَذَكَّرُونَ", transliteration: "Ya ayyuha allatheena amanoo la tadkhuloo buyootan ghayra buyootikum hatta tastanisoo watusallimoo AAala ahliha thalikum khayrun lakum laAAallakum tathakkaroona", transliterationB: "Yaaa aiyuhal lazeena aamanoo laa tadkhuloo buyootan ghaira buyootikum hatta tastaanisoo wa tusallimoo 'allaa ahlihaa; zaalikum khairul lakum la'allakum tazakkaroon", english: "O ye who believe! enter not houses other than your own, until ye have asked permission and saluted those in them: that is best for you, in order that ye may heed (what is seemly)", romanUrdu: "Aey logon jo iman laye ho, apne gharon ke siwa dusre gharon mein daakhil na hua karo jab tak ke ghar walon ki raza (ijazat) na lelo aur ghar walon par salaam na bhej lo. Yeh tareeqa tumhare liye behtar hai, tawakku hai ke tum iska khayal rakkhoge" },
    { number: 28, arabic: "فَإِن لَّمْ تَجِدُوا۟ فِيهَآ أَحَدًۭا فَلَا تَدْخُلُوهَا حَتَّىٰ يُؤْذَنَ لَكُمْ ۖ وَإِن قِيلَ لَكُمُ ٱرْجِعُوا۟ فَٱرْجِعُوا۟ ۖ هُوَ أَزْكَىٰ لَكُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ عَلِيمٌۭ", transliteration: "Fain lam tajidoo feeha ahadan fala tadkhulooha hatta yuthana lakum wain qeela lakumu irjiAAoo fairjiAAoo huwa azka lakum waAllahu bima taAAmaloona AAaleemun", transliterationB: "Fa il lam tajidoo feehaaa ahadan falaa tadkhuloohaa hattaa yu'zana lakum wa in qeela lakumurji'oo farji'oo huwa azkaa lakum; wallaahu bimaa ta'maloona 'Aleem", english: "If ye find no one in the house, enter not until permission is given to you: if ye are asked to go back, go back: that makes for greater purity for yourselves: and Allah knows well all that ye do", romanUrdu: "Phir agar wahan kisi ko na pao to daakhil na ho jabtak ke tumko ijazat na de di jaye, aur agar tumse kaha jaye ke wapas chale jao to wapas ho jao. Yeh tumhare liye zyada paakeeza tareeqa hai, aur jo kuch tum karte ho Allah usey khoob jaanta hai" },
    { number: 29, arabic: "لَّيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَدْخُلُوا۟ بُيُوتًا غَيْرَ مَسْكُونَةٍۢ فِيهَا مَتَٰعٌۭ لَّكُمْ ۚ وَٱللَّهُ يَعْلَمُ مَا تُبْدُونَ وَمَا تَكْتُمُونَ", transliteration: "Laysa AAalaykum junahun an tadkhuloo buyootan ghayra maskoonatin feeha mataAAun lakum waAllahu yaAAlamu ma tubdoona wama taktumoona", transliterationB: "Laisa 'alaikum junaahun ann tadkhuloo buyootan ghaira maskoonatin feeha mataa'ul lakum; wallaahu ya'lamu maa tubdoona wa maa taktumoon", english: "It is no fault on your part to enter houses not used for living in, which serve some (other) use for you: And Allah has knowledge of what ye reveal and what ye conceal", romanUrdu: "Albatta tumhare liye ismein koi muzahiqa (harm) nahin hai ke aisey gharon mein dakhil ho jao jo kisi ke rehne ki jagah na hon, aur jinmein tumhare faiyde (ya kaam) ki koi cheez ho, tum jo kuch zaahir karte ho aur jo kuch chupate ho sab ki Allah ko khabar hai" },
    { number: 30, arabic: "قُل لِّلْمُؤْمِنِينَ يَغُضُّوا۟ مِنْ أَبْصَٰرِهِمْ وَيَحْفَظُوا۟ فُرُوجَهُمْ ۚ ذَٰلِكَ أَزْكَىٰ لَهُمْ ۗ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا يَصْنَعُونَ", transliteration: "Qul lilmumineena yaghuddoo min absarihum wayahfathoo furoojahum thalika azka lahum inna Allaha khabeerun bima yasnaAAoona", transliterationB: "Qul lilmu' mineena yaghuuddoo min absaarihim wa yahfazoo furoojahum; zaalika azkaa lahum; innallaaha khabeerum bimaa yasna'oon", english: "Say to the believing men that they should lower their gaze and guard their modesty: that will make for greater purity for them: And Allah is well acquainted with all that they do", romanUrdu: "Aey Nabi, momin mardon se kaho ke apni nazarein bacha kar rakkhein aur apni sharm-gaahon ki hifazat karein, yeh unke liye zyada paakeeza tareeqa hai. Jo kuch woh karte hain Allah ussey bakhabar rehta hai" },
    { number: 31, arabic: "وَقُل لِّلْمُؤْمِنَٰتِ يَغْضُضْنَ مِنْ أَبْصَٰرِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا ۖ وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَىٰ جُيُوبِهِنَّ ۖ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا لِبُعُولَتِهِنَّ أَوْ ءَابَآئِهِنَّ أَوْ ءَابَآءِ بُعُولَتِهِنَّ أَوْ أَبْنَآئِهِنَّ أَوْ أَبْنَآءِ بُعُولَتِهِنَّ أَوْ إِخْوَٰنِهِنَّ أَوْ بَنِىٓ إِخْوَٰنِهِنَّ أَوْ بَنِىٓ أَخَوَٰتِهِنَّ أَوْ نِسَآئِهِنَّ أَوْ مَا مَلَكَتْ أَيْمَٰنُهُنَّ أَوِ ٱلتَّٰبِعِينَ غَيْرِ أُو۟لِى ٱلْإِرْبَةِ مِنَ ٱلرِّجَالِ أَوِ ٱلطِّفْلِ ٱلَّذِينَ لَمْ يَظْهَرُوا۟ عَلَىٰ عَوْرَٰتِ ٱلنِّسَآءِ ۖ وَلَا يَضْرِبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِن زِينَتِهِنَّ ۚ وَتُوبُوٓا۟ إِلَى ٱللَّهِ جَمِيعًا أَيُّهَ ٱلْمُؤْمِنُونَ لَعَلَّكُمْ تُفْلِحُونَ", transliteration: "Waqul lilmuminati yaghdudna min absarihinna wayahfathna furoojahunna wala yubdeena zeenatahunna illa ma thahara minha walyadribna bikhumurihinna AAala juyoobihinna wala yubdeena zeenatahunna illa libuAAoolatihinna aw abaihinna aw abai buAAoolatihinna aw abnaihinna aw abnai buAAoolatihinna aw ikhwanihinna aw banee ikhwanihinna aw banee akhawatihinna aw nisaihinna aw ma malakat aymanuhunna awi alttabiAAeena ghayri olee alirbati mina alrrijali awi alttifli allatheena lam yathharoo AAala AAawrati alnnisai wala yadribna biarjulihinna liyuAAlama ma yukhfeena min zeenatihinna watooboo ila Allahi jameeAAan ayyuha almuminoona laAAallakum tuflihoona", transliterationB: "Wa qul lilmu'minaati yaghdudna min absaarihinna wa yahfazna furoojahunna wa laa yubdeena zeenatahunna illaa maa zahara minhaa walyadribna bikhumurihinna 'alaa juyoobihinna wa laa yubdeena zeenatahunna illaa libu'oolatihinna aw aabaaa'i hinna aw aabaaa'i bu'oolati hinna aw abnaaa'ihinaa aw abnaaa'i bu'oolatihinnna aw ikhwaanihinnna aw baneee ikhwaanihinna aw banee akhawaatihinna aw nisaaa'i hinna aw maa malakat aimaanuhunna awit taabi'eena ghairi ilil irbati minar rijaali awit tiflillazeena lam yazharoo 'alaa 'awraatin nisaaa'i wala yadribnna bi arjulihinna min zeenatihinn; wa toobooo ilallaahi jammee'an aiyuhal mu'minoona la'allakum tuflihoon", english: "And say to the believing women that they should lower their gaze and guard their modesty; that they should not display their beauty and ornaments except what (must ordinarily) appear thereof; that they should draw their veils over their bosoms and not display their beauty except to their husbands, their fathers, their husband's fathers, their sons, their husbands' sons, their brothers or their brothers' sons, or their sisters' sons, or their women, or the slaves whom their right hands possess, or male servants free of physical needs, or small children who have no sense of the shame of sex; and that they should not strike their feet in order to draw attention to their hidden ornaments. And O ye Believers! turn ye all together towards Allah, that ye may attain Bliss", romanUrdu: "Aur (aey Nabi),momin auraton se kehdo ke apni nazrein bacha kar rakkhein, aur apni sharmgaahon ki hifazat karein, aur apna banao singhaar na dikhayein bajuz uske jo khud zaahir ho jaaye, aur apne seeno par apni oadniyon ke aanchal daale rahein, woh apna banaao singhar na zaahir karein magar in logon ke saamne: shohar ,baap, shoharon ke baap , apne betay, shoharon ke betay, bhai,bhaiyon ke betay, behno ke betay,apne mail-jhol ki auratein, apne mamluk(those in their possession), woh zeir-dast mard jo kisi aur qisam ki garz na rakhte hon, aur woh bacchey jo auraton ki posheeda baaton se abhi waqif na huey hon. Woh apne paon zameen par maarti hui na chala karein ke apni jo zeenat unhon ne chupa rakkhi ho uska logon ko ilm ho jaye. Aey momino, tum sab milkar Allah se toubah karo, tawaqqu hai ke falaah paogey" },
    { number: 32, arabic: "وَأَنكِحُوا۟ ٱلْأَيَٰمَىٰ مِنكُمْ وَٱلصَّٰلِحِينَ مِنْ عِبَادِكُمْ وَإِمَآئِكُمْ ۚ إِن يَكُونُوا۟ فُقَرَآءَ يُغْنِهِمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌۭ", transliteration: "Waankihoo alayama minkum waalssaliheena min AAibadikum waimaikum in yakoonoo fuqaraa yughnihimu Allahu min fadlihi waAllahu wasiAAun AAaleemun", transliterationB: "Wa ankihul ayaamaa minkum was saaliheena min 'ibaadikum wa imaa'kum; iny-yakoonoo fuqaraaa'a yughni himul laahu min fadlih; wal laahu Waasi'un 'Aleem", english: "Marry those among you who are single, or the virtuous ones among yourselves, male or female: if they are in poverty, Allah will give them means out of His grace: for Allah encompasseth all, and he knoweth all things", romanUrdu: "Tum mein se jo log mujarrad (single) hon aur tumhare laundi ghulamon mein se jo saaleh hon, unke nikah kardo. Agar woh gareeb hon to Allah apne fazal se unko gani kardega. Allah badi wusat (boundless resources) wala aur aleem hai" },
    { number: 33, arabic: "وَلْيَسْتَعْفِفِ ٱلَّذِينَ لَا يَجِدُونَ نِكَاحًا حَتَّىٰ يُغْنِيَهُمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ وَٱلَّذِينَ يَبْتَغُونَ ٱلْكِتَٰبَ مِمَّا مَلَكَتْ أَيْمَٰنُكُمْ فَكَاتِبُوهُمْ إِنْ عَلِمْتُمْ فِيهِمْ خَيْرًۭا ۖ وَءَاتُوهُم مِّن مَّالِ ٱللَّهِ ٱلَّذِىٓ ءَاتَىٰكُمْ ۚ وَلَا تُكْرِهُوا۟ فَتَيَٰتِكُمْ عَلَى ٱلْبِغَآءِ إِنْ أَرَدْنَ تَحَصُّنًۭا لِّتَبْتَغُوا۟ عَرَضَ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَمَن يُكْرِههُّنَّ فَإِنَّ ٱللَّهَ مِنۢ بَعْدِ إِكْرَٰهِهِنَّ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "WalyastaAAfifi allatheena la yajidoona nikahan hatta yughniyahumu Allahu min fadlihi waallatheena yabtaghoona alkitaba mimma malakat aymanukum fakatiboohum in AAalimtum feehim khayran waatoohum min mali Allahi allathee atakum wala tukrihoo fatayatikum AAala albighai in aradna tahassunan litabtaghoo AAarada alhayati alddunya waman yukrihhunna fainna Allaha min baAAdi ikrahihinna ghafoorun raheemun", transliterationB: "Wal yasta'fifil lazeena laa yajidoona nikaahan hata yughniyahumul laahu mi fadlih; wallazeena yabtaghoonal kitaaba mimmaa malakat aimaanukum fakaatiboohum in 'alimtum feehim khairanw wa aatoohum mimmaalil laahil lazeee aataakum; wa laa tukrihoo fatayaatikum 'alal bighaaa'i in aradna tahassunal litabtaghoo 'aradal hayaatid dunyaa; wa mai yukrihhunna fa innal laaha mim ba'di ikraahihinna Ghafoor Raheem", english: "Let those who find not the wherewithal for marriage keep themselves chaste, until Allah gives them means out of His grace. And if any of your slaves ask for a deed in writing (to enable them to earn their freedom for a certain sum), give them such a deed if ye know any good in them: yea, give them something yourselves out of the means which Allah has given to you. But force not your maids to prostitution when they desire chastity, in order that ye may make a gain in the goods of this life. But if anyone compels them, yet, after such compulsion, is Allah, Oft-Forgiving, Most Merciful (to them)", romanUrdu: "Aur jo nikah ka mauqa na paayein unhein chahiye ke iffat-maabi (continence/paak daamani) ikhtiyar karein, yahan tak ke Allah apne fazal se unko gani karde aur tumhare mamlukon mein (in your possession) se jo makatibat(emancipation) ki darkhwast karein unse makatibat karlo, agar tumhein maloom ho ke unke andar bhalayi hai, aur unko us maal mein se do jo Allah ne tumhein diya hai. Aur apni laundiyon (slave-girls ) ko apne duniyavi faiydon ki khatir qahba-gari (prostitution) par majboor na karo jabke woh khud paak daaman rehna chahti hon. Aur jo koi unko majboor karey to is jabr ke baad Allah unke liye gafoor o raheem hai" },
    { number: 34, arabic: "وَلَقَدْ أَنزَلْنَآ إِلَيْكُمْ ءَايَٰتٍۢ مُّبَيِّنَٰتٍۢ وَمَثَلًۭا مِّنَ ٱلَّذِينَ خَلَوْا۟ مِن قَبْلِكُمْ وَمَوْعِظَةًۭ لِّلْمُتَّقِينَ", transliteration: "Walaqad anzalna ilaykum ayatin mubayyinatin wamathalan mina allatheena khalaw min qablikum wamawAAithatan lilmuttaqeena", transliterationB: "Wa laqad anzalnaaa ilaikum Aayaatim mubaiyinaatinw wa masalam minnal lazeena khalaw min qablikum wa maw'izatal lilmuttaqeen", english: "We have already sent down to you verses making things clear, an illustration from (the story of) people who passed away before you, and an admonition for those who fear (Allah)", romanUrdu: "Humne saaf saaf hidayat dene wali aayat tumhare paas bhej di hain, aur un qaumon ki ibratnaak misalein bhi hum tumhare saamne pesh kar chuke hain jo tumse pehle ho guzri hain. Aur woh naseehatein humne kardi hain jo darne walon ke liye hoti hain" },
    { number: 35, arabic: "۞ ٱللَّهُ نُورُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ مَثَلُ نُورِهِۦ كَمِشْكَوٰةٍۢ فِيهَا مِصْبَاحٌ ۖ ٱلْمِصْبَاحُ فِى زُجَاجَةٍ ۖ ٱلزُّجَاجَةُ كَأَنَّهَا كَوْكَبٌۭ دُرِّىٌّۭ يُوقَدُ مِن شَجَرَةٍۢ مُّبَٰرَكَةٍۢ زَيْتُونَةٍۢ لَّا شَرْقِيَّةٍۢ وَلَا غَرْبِيَّةٍۢ يَكَادُ زَيْتُهَا يُضِىٓءُ وَلَوْ لَمْ تَمْسَسْهُ نَارٌۭ ۚ نُّورٌ عَلَىٰ نُورٍۢ ۗ يَهْدِى ٱللَّهُ لِنُورِهِۦ مَن يَشَآءُ ۚ وَيَضْرِبُ ٱللَّهُ ٱلْأَمْثَٰلَ لِلنَّاسِ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۭ", transliteration: "Allahu nooru alssamawati waalardi mathalu noorihi kamishkatin feeha misbahun almisbahu fee zujajatin alzzujajatu kaannaha kawkabun durriyyun yooqadu min shajaratin mubarakatin zaytoonatin la sharqiyyatin wala gharbiyyatin yakadu zaytuha yudeeo walaw lam tamsashu narun noorun AAala noorin yahdee Allahu linoorihi man yashao wayadribu Allahu alamthala lilnnasi waAllahu bikulli shayin AAaleemun", transliterationB: "Allaahu noorus samaawaati wal ard; masalu noorihee kamishkaatin feehaa misbaah; almisbaahu fee zujaajatin azzujaajatu ka annahaa kawkabun durriyyuny yooqadu min shajaratim mubaarakatin zaitoonatil laa shariqiyyatinw wa laa gharbiyyatiny yakaadu zaituhaa yudeee'u wa law alm tamsashu naar; noorun 'alaa noor; yahdil laahu linoorihee mai yashaaa'; wa yadribul laahul amsaala linnaas; wallaahu bikulli shai'in Aleem", english: "Allah is the Light of the heavens and the earth. The Parable of His Light is as if there were a Niche and within it a Lamp: the Lamp enclosed in Glass: the glass as it were a brilliant star: Lit from a blessed Tree, an Olive, neither of the east nor of the west, whose oil is well-nigh luminous, though fire scarce touched it: Light upon Light! Allah doth guide whom He will to His Light: Allah doth set forth Parables for men: and Allah doth know all things", romanUrdu: "Allah aasmano aur zameen ka noor hai ( kayinaat mein) uske noor ki misaal aisi hai jaise ek taaq mein chiraag rakha hua ho,chiraag ek fanoos mein ho(in a glass shade), fanoos (glass shade) ka haal yeh ho ke jaise moti ki tarah chamakta hua taara, aur woh chiraag zaitoon ke ek aise mubarak darakht ke tail(oil) se roshan kiya jata ho jo na sharqi (eastern) ho na garabi (western), jiska tail (oil) aap hi aap bhadka padta ho chahey aag usko na lagey, ( is taraah) roshni par roshni (badhne ke tamaam asbaab jamaa ho gaye hon). Allah apne noor ki taraf jiski chahta hai rehnumayi farmata hai. Woh logon ko misaalon se baat samjhata hai, woh har cheez se khoob waqif hai" },
    { number: 36, arabic: "فِى بُيُوتٍ أَذِنَ ٱللَّهُ أَن تُرْفَعَ وَيُذْكَرَ فِيهَا ٱسْمُهُۥ يُسَبِّحُ لَهُۥ فِيهَا بِٱلْغُدُوِّ وَٱلْءَاصَالِ", transliteration: "Fee buyootin athina Allahu an turfaAAa wayuthkara feeha ismuhu yusabbihu lahu feeha bialghuduwwi waalasali", transliterationB: "Fee buyootin azinal laahu an turfa'a wa yuzkara feehasmuhoo yusabbihu lahoo feehaa bilghuduwwi wal aasaal", english: "(Lit is such a Light) in houses, which Allah hath permitted to be raised to honour; for the celebration, in them, of His name: In them is He glorified in the mornings and in the evenings, (again and again)", romanUrdu: "(Uske noor ki taraf hidayat paney waley) un gharon mein paye jatey hain jinhein buland karne ka aur jin mein apne naam ki yaad ka Allah ne izan (ijazat) diya hai" },
    { number: 37, arabic: "رِجَالٌۭ لَّا تُلْهِيهِمْ تِجَٰرَةٌۭ وَلَا بَيْعٌ عَن ذِكْرِ ٱللَّهِ وَإِقَامِ ٱلصَّلَوٰةِ وَإِيتَآءِ ٱلزَّكَوٰةِ ۙ يَخَافُونَ يَوْمًۭا تَتَقَلَّبُ فِيهِ ٱلْقُلُوبُ وَٱلْأَبْصَٰرُ", transliteration: "Rijalun la tulheehim tijaratun wala bayAAun AAan thikri Allahi waiqami alssalati waeetai alzzakati yakhafoona yawman tataqallabu feehi alquloobu waalabsaru", transliterationB: "Rinjaalul laa tulheehim tijaaratunw wa laa bai'un 'an zikril laahi wa iqaamis Salaati wa eetaaa'iz Zakaati yakkhaafoona Yawman tataqallabu feehil quloobu wal absaar", english: "By men whom neither traffic nor merchandise can divert from the Remembrance of Allah, nor from regular Prayer, nor from the practice of regular Charity: Their (only) fear is for the Day when hearts and eyes will be transformed (in a world wholly new)", romanUrdu: "Un mein aisey log subah o shaam uski tasbeeh karte hain jinhein tijarat aur khareed o farokht Allah ki yaad se aur iqamat e namaaz o adaaye zakaat se gaafil nahin kardeti. Woh us din se darte rehte hain jismein dil ulatne aur deedhey pathra janey ki (eyes will become petrified) naubat aa jayegi" },
    { number: 38, arabic: "لِيَجْزِيَهُمُ ٱللَّهُ أَحْسَنَ مَا عَمِلُوا۟ وَيَزِيدَهُم مِّن فَضْلِهِۦ ۗ وَٱللَّهُ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍۢ", transliteration: "Liyajziyahumu Allahu ahsana ma AAamiloo wayazeedahum min fadlihi waAllahu yarzuqu man yashao bighayri hisabin", transliterationB: "Liyajziyahumul laahu ahsana maa 'amiloo wa yazeedahum min fadlih; wal laahu yarzuqu mai yashaaa'u bighairi hisaab", english: "That Allah may reward them according to the best of their deeds, and add even more for them out of His Grace: for Allah doth provide for those whom He will, without measure", romanUrdu: "(Aur woh yeh sabkuch isliye karte hain) taa-ke Allah unke behtareen aamaal ki jaza unko de aur mazeed apne fazal se nawaze. Allah jisey chahta hai be-hisaab deta hai" },
    { number: 39, arabic: "وَٱلَّذِينَ كَفَرُوٓا۟ أَعْمَٰلُهُمْ كَسَرَابٍۭ بِقِيعَةٍۢ يَحْسَبُهُ ٱلظَّمْـَٔانُ مَآءً حَتَّىٰٓ إِذَا جَآءَهُۥ لَمْ يَجِدْهُ شَيْـًۭٔا وَوَجَدَ ٱللَّهَ عِندَهُۥ فَوَفَّىٰهُ حِسَابَهُۥ ۗ وَٱللَّهُ سَرِيعُ ٱلْحِسَابِ", transliteration: "Waallatheena kafaroo aAAmaluhum kasarabin biqeeAAatin yahsabuhu alththamanu maan hatta itha jaahu lam yajidhu shayan wawajada Allaha AAindahu fawaffahu hisabahu waAllahu sareeAAu alhisabi", transliterationB: "Wallazeena kafarooo a'maaluhum kasaraabim biqee'atiny yahsabuhuz zamaanu maaa'an hattaaa izaa jaaa'ahoo lam yajid hu shai'anw wa wajadal laaha 'indahoo fa waffaahu hisaabah; wallaahu saree'ul hisaab", english: "But the Unbelievers,- their deeds are like a mirage in sandy deserts, which the man parched with thirst mistakes for water; until when he comes up to it, he finds it to be nothing: But he finds Allah (ever) with him, and Allah will pay him his account: and Allah is swift in taking account", romanUrdu: "(Iske baraks) jinhon ne kufr kiya unke aamal ki misaal aisi hai jaise dasht e bay-aab mein saraab ka pyasa (likened to a mirage in a waterless desert ) usko pani samajhe huey tha, magar jab wahan pahuncha to kuch na paya, balke wahan usne Allah ko maujood paya, jisne uska poora poora hisaab chuka diya. Aur Allah ko hisaab letay dair nahin lagti" },
    { number: 40, arabic: "أَوْ كَظُلُمَٰتٍۢ فِى بَحْرٍۢ لُّجِّىٍّۢ يَغْشَىٰهُ مَوْجٌۭ مِّن فَوْقِهِۦ مَوْجٌۭ مِّن فَوْقِهِۦ سَحَابٌۭ ۚ ظُلُمَٰتٌۢ بَعْضُهَا فَوْقَ بَعْضٍ إِذَآ أَخْرَجَ يَدَهُۥ لَمْ يَكَدْ يَرَىٰهَا ۗ وَمَن لَّمْ يَجْعَلِ ٱللَّهُ لَهُۥ نُورًۭا فَمَا لَهُۥ مِن نُّورٍ", transliteration: "Aw kathulumatin fee bahrin lujjiyyin yaghshahu mawjun min fawqihi mawjun min fawqihi sahabun thulumatun baAAduha fawqa baAAdin itha akhraja yadahu lam yakad yaraha waman lam yajAAali Allahu lahu nooran fama lahu min noorin", transliterationB: "Aw kazulumaatin fee bahril lujjiyyiny yaghshaahu mawjum min fawqihee mawjum min fawqihee mawjum min fawqihee sahaab; zulumatum ba'duhaa fawqa ba'din izaaa akhraja yadahoo lam yakad yaraahaa wa mal lam yaj'alil laahu lahoo noora famaa lahoo min noor", english: "Or (the Unbelievers' state) is like the depths of darkness in a vast deep ocean, overwhelmed with billow topped by billow, topped by (dark) clouds: depths of darkness, one above another: if a man stretches out his hands, he can hardly see it! for any to whom Allah giveth not light, there is no light", romanUrdu: "Ya phir uski misaal aisi hai jaise ek gehre samandar mein andhera , ke upar ek mauj chayi hui hai, uspar ek aur mauj, aur uske upar baadal,tareeki(andhera) par tareeki (darkness) musallat hai, aadmi apna haath nikale to usey bhi na dekhne paye. Jisey Allah noor na bakshay uske liye phir koi noor nahin" },
    { number: 41, arabic: "أَلَمْ تَرَ أَنَّ ٱللَّهَ يُسَبِّحُ لَهُۥ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱلطَّيْرُ صَٰٓفَّٰتٍۢ ۖ كُلٌّۭ قَدْ عَلِمَ صَلَاتَهُۥ وَتَسْبِيحَهُۥ ۗ وَٱللَّهُ عَلِيمٌۢ بِمَا يَفْعَلُونَ", transliteration: "Alam tara anna Allaha yusabbihu lahu man fee alssamawati waalardi waalttayru saffatin kullun qad AAalima salatahu watasbeehahu waAllahu AAaleemun bima yafAAaloona", transliterationB: "Alam tara annal laaha yusabbihu lahoo man fissamaawaati wal ardi wat tairu saaaffaatim kullun qad 'alima Salaatahoo wa tasbeehah; wallaahu 'aleemum bimaa yaf'aloon", english: "Seest thou not that it is Allah Whose praises all beings in the heavens and on earth do celebrate, and the birds (of the air) with wings outspread? Each one knows its own (mode of) prayer and praise. And Allah knows well all that they do", romanUrdu: "Kya tum dekhte nahin ho ke Allah ki tasbeeh kar rahey hain woh sab jo aasmano aur zameen mein hain aur woh parinde jo parr phaylaye udd rahe hain? Har ek apni namaz aur tasbeeh ka tareeqa jaanta hai, aur ye sab jo kuch karte hain Allah ussey baa-khabar rehta hai" },
    { number: 42, arabic: "وَلِلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَإِلَى ٱللَّهِ ٱلْمَصِيرُ", transliteration: "Walillahi mulku alssamawati waalardi waila Allahi almaseeru", transliterationB: "Wa lillaahi mulkus samaawaati wal ardi wa ilal laahil maseer", english: "Yea, to Allah belongs the dominion of the heavens and the earth; and to Allah is the final goal (of all)", romanUrdu: "Aasmaano aur zameen ki baadshahi Allah hi ke liye hai aur usi ki taraf sabko palatna hai" },
    { number: 43, arabic: "أَلَمْ تَرَ أَنَّ ٱللَّهَ يُزْجِى سَحَابًۭا ثُمَّ يُؤَلِّفُ بَيْنَهُۥ ثُمَّ يَجْعَلُهُۥ رُكَامًۭا فَتَرَى ٱلْوَدْقَ يَخْرُجُ مِنْ خِلَٰلِهِۦ وَيُنَزِّلُ مِنَ ٱلسَّمَآءِ مِن جِبَالٍۢ فِيهَا مِنۢ بَرَدٍۢ فَيُصِيبُ بِهِۦ مَن يَشَآءُ وَيَصْرِفُهُۥ عَن مَّن يَشَآءُ ۖ يَكَادُ سَنَا بَرْقِهِۦ يَذْهَبُ بِٱلْأَبْصَٰرِ", transliteration: "Alam tara anna Allaha yuzjee sahaban thumma yuallifu baynahu thumma yajAAaluhu rukaman fatara alwadqa yakhruju min khilalihi wayunazzilu mina alssamai min jibalin feeha min baradin fayuseebu bihi man yashao wayasrifuhu AAan man yashao yakadu sana barqihi yathhabu bialabsari", transliterationB: "Alam tara annal laaha yuzjee sahaaban summa yu'allifu bainahoo summa yaj'aluhoo rukaaman fataral wadqa yakhruju min khilaalihee wa yunazzilu minas samaaa'i min jibaalin feehaa mim barain fa yuseebu bihee mai yashaaa'u wa yasrifuhoo 'am mai yashaaa'u yakkaadu sanaa barqihee yazhabu bil absaar", english: "Seest thou not that Allah makes the clouds move gently, then joins them together, then makes them into a heap? - then wilt thou see rain issue forth from their midst. And He sends down from the sky mountain masses (of clouds) wherein is hail: He strikes therewith whom He pleases and He turns it away from whom He pleases, the vivid flash of His lightning well-nigh blinds the sight", romanUrdu: "Kya tum dekhte nahin ho ke Allah baadal ko aahista aahista chalata hai, phir uske tukdon ko baaham jodta hai, phir usey sameit kar ek kaseef abr (mass of thick cloud) bana deta hai. Phir tum dekhte ho ke uske khaul mein se baarish ke qatre tapakte chale jatey hain aur woh aasman se , un pahadon ki badaulat jo usmein buland hain, aulay (hail / ice) barsata hai, phir jisey chahta hai unka nuqsaan pahuchata hai aur jisey chahta hai unse bacha leta hai, uski bijli ki chamak nigaahon ko kheira (dazzles the eyes) kiye deti hai" },
    { number: 44, arabic: "يُقَلِّبُ ٱللَّهُ ٱلَّيْلَ وَٱلنَّهَارَ ۚ إِنَّ فِى ذَٰلِكَ لَعِبْرَةًۭ لِّأُو۟لِى ٱلْأَبْصَٰرِ", transliteration: "Yuqallibu Allahu allayla waalnnahara inna fee thalika laAAibratan liolee alabsari", transliterationB: "Yuqallibul laahul laila wannahaar; inna fee zaalika la'ibratal li ulil absaar", english: "It is Allah Who alternates the Night and the Day: verily in these things is an instructive example for those who have vision", romanUrdu: "Raat aur din ka ulat pher wahi kar raha hai. Ismein ek sabaq hai aankhon walon ke liye" },
    { number: 45, arabic: "وَٱللَّهُ خَلَقَ كُلَّ دَآبَّةٍۢ مِّن مَّآءٍۢ ۖ فَمِنْهُم مَّن يَمْشِى عَلَىٰ بَطْنِهِۦ وَمِنْهُم مَّن يَمْشِى عَلَىٰ رِجْلَيْنِ وَمِنْهُم مَّن يَمْشِى عَلَىٰٓ أَرْبَعٍۢ ۚ يَخْلُقُ ٱللَّهُ مَا يَشَآءُ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "WaAllahu khalaqa kulla dabbatin min main faminhum man yamshee AAala batnihi waminhum man yamshee AAala rijlayni waminhum man yamshee AAala arbaAAin yakhluqu Allahu ma yashao inna Allaha AAala kulli shayin qadeerun", transliterationB: "Wallaahu khalaqa kulla daaabbatim mim maaa'in faminhum mai yamshee 'alaa batnihee wa minhum mai yamshee 'alaa rijlaine wa minhum mai yamshee 'alaaa arba'; yakhluqul laahu maa yashaaa'; innal laaha 'alaa kulli shai'in Qadeer", english: "And Allah has created every animal from water: of them there are some that creep on their bellies; some that walk on two legs; and some that walk on four. Allah creates what He wills for verily Allah has power over all things", romanUrdu: "Aur Allah ne har jaandaar ek tarah ke pani se paida kiya, koi pait ke bal chal raha hai to koi do taangon (two legs) par aur koi chaar taangon par. Jo kuch woh chahta hai paida karta hai, woh har cheez par qadir hai" },
    { number: 46, arabic: "لَّقَدْ أَنزَلْنَآ ءَايَٰتٍۢ مُّبَيِّنَٰتٍۢ ۚ وَٱللَّهُ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Laqad anzalna ayatin mubayyinatin waAllahu yahdee man yashao ila siratin mustaqeemin", transliterationB: "Laqad anzalnaaa Aayaatim mubaiyinaat; wallaahu yahdee mai yashaaa'u ilaa Siraatim Mustaqeem", english: "We have indeed sent down signs that make things manifest: and Allah guides whom He wills to a way that is straight", romanUrdu: "Humne saaf saaf haqeeqat batane wali aayat nazil kardi hai, aagey siraate mustaqeem ki taraf hidayat Allah hi jisey chahta hai deta hai" },
    { number: 47, arabic: "وَيَقُولُونَ ءَامَنَّا بِٱللَّهِ وَبِٱلرَّسُولِ وَأَطَعْنَا ثُمَّ يَتَوَلَّىٰ فَرِيقٌۭ مِّنْهُم مِّنۢ بَعْدِ ذَٰلِكَ ۚ وَمَآ أُو۟لَٰٓئِكَ بِٱلْمُؤْمِنِينَ", transliteration: "Wayaqooloona amanna biAllahi wabialrrasooli waataAAna thumma yatawalla fareequn minhum min baAAdi thalika wama olaika bialmumineena", transliterationB: "Wa yaqooloona aamannaa billaahi wa bir Rasooli wa ata'naa summa yatawallaa fareequm minhum mim ba'di zaalik; wa maaa ulaaa'ika bilmu'mineen", english: "They say, \"We believe in Allah and in the messenger, and we obey\": but even after that, some of them turn away: they are not (really) Believers", romanUrdu: "Yeh log kehte hain ke hum iman laye Allah aur Rasool par aur humne itaat qabool ki, magar iske baad inmein se ek giroh (itaat se) mooh moad jaata hai, aisey log hargiz momin nahin hain" },
    { number: 48, arabic: "وَإِذَا دُعُوٓا۟ إِلَى ٱللَّهِ وَرَسُولِهِۦ لِيَحْكُمَ بَيْنَهُمْ إِذَا فَرِيقٌۭ مِّنْهُم مُّعْرِضُونَ", transliteration: "Waitha duAAoo ila Allahi warasoolihi liyahkuma baynahum itha fareequn minhum muAAridoona", transliterationB: "Wa izaa du'ooo ilal laahi wa Rasoolihee li yahkuma bainahum izaa fareequm minhum mu'ridoon", english: "When they are summoned to Allah and His messenger, in order that He may judge between them, behold some of them decline (to come)", romanUrdu: "Jab inko bulaya jata hai Allah aur Rasool ki taraf, taa-ke Rasool inke aapas ke muqaddame ka faisla karey to inmein se ek fareeq katra jata (turns away) hai" },
    { number: 49, arabic: "وَإِن يَكُن لَّهُمُ ٱلْحَقُّ يَأْتُوٓا۟ إِلَيْهِ مُذْعِنِينَ", transliteration: "Wain yakun lahumu alhaqqu yatoo ilayhi muthAAineena", transliterationB: "Wa iny-yakul lahumul haqqu yaatooo ilaihi muz'ineen", english: "But if the right is on their side, they come to him with all submission", romanUrdu: "Albatta agar haqq unki muafiqat (on their side) mein ho to Rasool ke paas baday itaat-kish (obedience) ban kar aa jatey hain" },
    { number: 50, arabic: "أَفِى قُلُوبِهِم مَّرَضٌ أَمِ ٱرْتَابُوٓا۟ أَمْ يَخَافُونَ أَن يَحِيفَ ٱللَّهُ عَلَيْهِمْ وَرَسُولُهُۥ ۚ بَلْ أُو۟لَٰٓئِكَ هُمُ ٱلظَّٰلِمُونَ", transliteration: "Afee quloobihim maradun ami irtaboo am yakhafoona an yaheefa Allahu AAalayhim warasooluhu bal olaika humu alththalimoona", transliterationB: "Afee quloobihim ma radun amirtaabooo am yakhaafoona ani yaheefallaahu 'alaihim wa Rasooluh; bal ulaaa'ika humuz zaalimoon", english: "Is it that there is a disease in their hearts? or do they doubt, or are they in fear, that Allah and His Messenger will deal unjustly with them? Nay, it is they themselves who do wrong", romanUrdu: "Kya unke dilon ko (munafiqat ka) rog laga hua hai? Ya yeh shakk mein padey huey hain? Ya inko yeh khauf hai ke Allah aur uska Rasool inpar zulm karega? Asal baat yeh hai ke zaalim to yeh log khud hain" },
    { number: 51, arabic: "إِنَّمَا كَانَ قَوْلَ ٱلْمُؤْمِنِينَ إِذَا دُعُوٓا۟ إِلَى ٱللَّهِ وَرَسُولِهِۦ لِيَحْكُمَ بَيْنَهُمْ أَن يَقُولُوا۟ سَمِعْنَا وَأَطَعْنَا ۚ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Innama kana qawla almumineena itha duAAoo ila Allahi warasoolihi liyahkuma baynahum an yaqooloo samiAAna waataAAna waolaika humu almuflihoona", transliterationB: "Innamaa kaana qawlal mu'mineena izaa du'ooo ilal laahi wa Rasoolihee li yahkuma bainahum ai yaqooloo sami'naa wa ata'naa; wa ulaaa'ika humul muflihoon", english: "The answer of the Believers, when summoned to Allah and His Messenger, in order that He may judge between them, is no other than this: they say, \"We hear and we obey\": it is such as these that will attain felicity", romanUrdu: "Iman laney walon ka kaam to yeh hai ke jab woh Allah aur Rasool ki taraf bulaye jayein taa-ke Rasool unke muqaddame ka faisla karey to woh kahein ke humne suna aur itaat ki, aisey hi log falaah paaney waley hain" },
    { number: 52, arabic: "وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ وَيَخْشَ ٱللَّهَ وَيَتَّقْهِ فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَآئِزُونَ", transliteration: "Waman yutiAAi Allaha warasoolahu wayakhsha Allaha wayattaqhi faolaika humu alfaizoona", transliterationB: "Wa mai yuti'il laaha wa Rasoolahoo wa yakhshal laaha wa yattaqhi fa ulaaa'ika humul faaa'izoon", english: "It is such as obey Allah and His Messenger, and fear Allah and do right, that will win (in the end)", romanUrdu: "Aur kamiyab wahi hain jo Allah aur Rasool ki farma bardari karein aur Allah se darein aur uski nafarmani se bachein" },
    { number: 53, arabic: "۞ وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَٰنِهِمْ لَئِنْ أَمَرْتَهُمْ لَيَخْرُجُنَّ ۖ قُل لَّا تُقْسِمُوا۟ ۖ طَاعَةٌۭ مَّعْرُوفَةٌ ۚ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا تَعْمَلُونَ", transliteration: "Waaqsamoo biAllahi jahda aymanihim lain amartahum layakhrujunna qul la tuqsimoo taAAatun maAAroofatun inna Allaha khabeerun bima taAAmaloona", transliterationB: "Wa aqsamoo billaahi jahda aimaanihim la'in amartahum la yakhrujunna qul laa tuqsimoo taa'atum ma'roofah innal laaha khabeerum bimaa ta'maloon", english: "They swear their strongest oaths by Allah that, if only thou wouldst command them, they would leave (their homes). Say: \"Swear ye not; Obedience is (more) reasonable; verily, Allah is well acquainted with all that ye do", romanUrdu: "Yeh (munafiq) Allah ke naam se kadi kadi kasmein kha kar kehte hain ke “ aap hukum dein to hum gharon se nikal khade hon” . Insey kaho “kasamein na khao , tumhari itaat ka haal maloom hai, tumhare kartooton se Allah be-khabar nahin hai”" },
    { number: 54, arabic: "قُلْ أَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ ۖ فَإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْهِ مَا حُمِّلَ وَعَلَيْكُم مَّا حُمِّلْتُمْ ۖ وَإِن تُطِيعُوهُ تَهْتَدُوا۟ ۚ وَمَا عَلَى ٱلرَّسُولِ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ", transliteration: "Qul ateeAAoo Allaha waateeAAoo alrrasoola fain tawallaw fainnama AAalayhi ma hummila waAAalaykum ma hummiltum wain tuteeAAoohu tahtadoo wama AAala alrrasooli illa albalaghu almubeena", transliterationB: "Qul atee'ul laaha wa atee'ur Rasoola fa in tawallaw fa innamaa 'alaihi maa hummila wa 'alaikum maa hummiltum wa in tutee'oohu tahtadoo; wa maa'alar Rasooli illal balaaghul mubeen", english: "Say: \"Obey Allah, and obey the Messenger: but if ye turn away, he is only responsible for the duty placed on him and ye for that placed on you. If ye obey him, ye shall be on right guidance. The Messenger's duty is only to preach the clear (Message)", romanUrdu: "Kaho, “Allah ke mutii bano (obey Allah) aur Rasool ke tabey farmaan bankar raho , lekin agar tum mooh pherte ho to khoob samajh lo ke Rasool par jis farz ka baar rakkha gaya hai uska zimmedar woh hai aur tumpar jis farz ka baar dala gaya hai uske zimmedar tum ho. Uski itaat karoge to khud hi hidayat paogey warna Rasool ki zimmedari issey zyada kuch nahin hai ke saaf saaf hukum pahuncha de”" },
    { number: 55, arabic: "وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ مِنكُمْ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَيَسْتَخْلِفَنَّهُمْ فِى ٱلْأَرْضِ كَمَا ٱسْتَخْلَفَ ٱلَّذِينَ مِن قَبْلِهِمْ وَلَيُمَكِّنَنَّ لَهُمْ دِينَهُمُ ٱلَّذِى ٱرْتَضَىٰ لَهُمْ وَلَيُبَدِّلَنَّهُم مِّنۢ بَعْدِ خَوْفِهِمْ أَمْنًۭا ۚ يَعْبُدُونَنِى لَا يُشْرِكُونَ بِى شَيْـًۭٔا ۚ وَمَن كَفَرَ بَعْدَ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَٰسِقُونَ", transliteration: "WaAAada Allahu allatheena amanoo minkum waAAamiloo alssalihati layastakhlifannahum fee alardi kama istakhlafa allatheena min qablihim walayumakkinanna lahum deenahumu allathee irtada lahum walayubaddilannahum min baAAdi khawfihim amnan yaAAbudoonanee la yushrikoona bee shayan waman kafara baAAda thalika faolaika humu alfasiqoona", transliterationB: "Wa'adal laahul lazeena aamanoo minkum wa 'amilus saalihaati la yastakhlifan nahum fil ardi kamastakh lafal lazeena min qablihim wa la yumakkinanna lahum deenahumul lazir tadaa lahum wa la yubaddilannahum mim ba'di khawfihim amnaa; ya'budoonanee laayushrikoona bee shai'aa; wa man kafara ba'da zaalika fa ulaaa'ika humul faasiqoon", english: "Allah has promised, to those among you who believe and work righteous deeds, that He will, of a surety, grant them in the land, inheritance (of power), as He granted it to those before them; that He will establish in authority their religion - the one which He has chosen for them; and that He will change (their state), after the fear in which they (lived), to one of security and peace: 'They will worship Me (alone) and not associate aught with Me. 'If any do reject Faith after this, they are rebellious and wicked", romanUrdu: "Allah ne wada farmaya hai tum mein se un logon ke saath jo iman layein aur neik amal karein ke woh unko usi tarah zameen mein khalifa banayega jis tarah unse pehle guzre huey logon ko bana chuka hai , unke liye unke us deen (religion) ko mazboot buniyadon par qayam kardega jisey Allah taala ne unke haqq mein pasand kiya hai, aur unki (maujooda) halat e khauf ko aman se badal dega, bas woh meri bandagi karein aur mere saath kisi ko shareek na karein, aur jo iske baad kufr karey to aise hi log faasiq hain" },
    { number: 56, arabic: "وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَأَطِيعُوا۟ ٱلرَّسُولَ لَعَلَّكُمْ تُرْحَمُونَ", transliteration: "Waaqeemoo alssalata waatoo alzzakata waateeAAoo alrrasoola laAAallakum turhamoona", transliterationB: "Wa aqeemus Salaata wa aatuz Zakaata wa atee'ur Rasoola la'allakum turhamoon", english: "So establish regular Prayer and give regular Charity; and obey the Messenger; that ye may receive mercy", romanUrdu: "Namaz qayam karo, zakat do, aur Rasool ki itaat karo, umeed hai ke tumpar reham kiya jayega" },
    { number: 57, arabic: "لَا تَحْسَبَنَّ ٱلَّذِينَ كَفَرُوا۟ مُعْجِزِينَ فِى ٱلْأَرْضِ ۚ وَمَأْوَىٰهُمُ ٱلنَّارُ ۖ وَلَبِئْسَ ٱلْمَصِيرُ", transliteration: "La tahsabanna allatheena kafaroo muAAjizeena fee alardi wamawahumu alnnaru walabisa almaseeru", transliterationB: "Laa tahsabannal lazeena kafaroo mu'jizeena fil ard; wa maawaahumun Naaru wa labi'sal maseer", english: "Never think thou that the Unbelievers are going to frustrate (Allah's Plan) on earth: their abode is the Fire,- and it is indeed an evil refuge", romanUrdu: "Jo log kufr kar rahey hain unke mautaaliq is galat fahmi mein na raho ke woh zameen mein Allah ko aajiz(frustrate) kardenge, unka thikana dozakh hai aur woh bada hi bura thikana hai" },
    { number: 58, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لِيَسْتَـْٔذِنكُمُ ٱلَّذِينَ مَلَكَتْ أَيْمَٰنُكُمْ وَٱلَّذِينَ لَمْ يَبْلُغُوا۟ ٱلْحُلُمَ مِنكُمْ ثَلَٰثَ مَرَّٰتٍۢ ۚ مِّن قَبْلِ صَلَوٰةِ ٱلْفَجْرِ وَحِينَ تَضَعُونَ ثِيَابَكُم مِّنَ ٱلظَّهِيرَةِ وَمِنۢ بَعْدِ صَلَوٰةِ ٱلْعِشَآءِ ۚ ثَلَٰثُ عَوْرَٰتٍۢ لَّكُمْ ۚ لَيْسَ عَلَيْكُمْ وَلَا عَلَيْهِمْ جُنَاحٌۢ بَعْدَهُنَّ ۚ طَوَّٰفُونَ عَلَيْكُم بَعْضُكُمْ عَلَىٰ بَعْضٍۢ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌۭ", transliteration: "Ya ayyuha allatheena amanoo liyastathinkumu allatheena malakat aymanukum waallatheena lam yablughoo alhuluma minkum thalatha marratin min qabli salati alfajri waheena tadaAAoona thiyabakum mina alththaheerati wamin baAAdi salati alAAishai thalathu AAawratin lakum laysa AAalaykum wala AAalayhim junahun baAAdahunna tawwafoona AAalaykum baAAdukum AAala baAAdin kathalika yubayyinu Allahu lakumu alayati waAllahu AAaleemun hakeemun", transliterationB: "Yaaa aiyuhal lazeena aamanoo li yastaazinkumul lazeena malakat aimaanukum wallazeena lam yablughul huluma minkum salaasa marraat; min qabli Salaatil Fajri wa heena tada'oona siyaa bakum minaz zaheerati wa mim ba'di Salaatil Ishaaa'; salaasu 'awraatil lakum; laisa 'alaikum wa laa 'alaihim junaahum ba'dahunn; tawwaafoona 'alaikum ba'dukum 'alaa ba'd; kazaalika yubaiyinul laahu lakumul aayaat wallaahu 'Aleemun Hakeem", english: "O ye who believe! let those whom your right hands possess, and the (children) among you who have not come of age ask your permission (before they come to your presence), on three occasions: before morning prayer; the while ye doff your clothes for the noonday heat; and after the late-night prayer: these are your three times of undress: outside those times it is not wrong for you or for them to move about attending to each other: Thus does Allah make clear the Signs to you: for Allah is full of knowledge and wisdom", romanUrdu: "Aey logon jo iman laaye ho, lazim hai ke tumhare mamluk (your slaves) aur tumhare woh bacchey jo abhi aqal ki hadd ko (sex conscious /puberty) nahin pahunchey hain, teen auqat mein ijazat lekar tumhare paas aaya karein: subah ki namaz se pehle, aur dopahar ko jabke tum kapde utar kar rakh detey ho, aur ishaa ki namaz ke baad. Yeh teen waqt tumhare liye purdey ke waqt hain. Inke baad woh bila ijazat aayein to na tumpar koi gunaah hai na unpar, tumhein ek dusre ke paas baar baar aana hi hota hai. Is tarah Allah tumhare liye apne irshadaat ki tawzeeh (wazeh) karta hai, aur woh aleem o hakeem hai" },
    { number: 59, arabic: "وَإِذَا بَلَغَ ٱلْأَطْفَٰلُ مِنكُمُ ٱلْحُلُمَ فَلْيَسْتَـْٔذِنُوا۟ كَمَا ٱسْتَـْٔذَنَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَٰتِهِۦ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌۭ", transliteration: "Waitha balagha alatfalu minkumu alhuluma falyastathinoo kama istathana allatheena min qablihim kathalika yubayyinu Allahu lakum ayatihi waAllahu AAaleemun hakeemun", transliterationB: "Wa izaa balaghal atfaalu minkumul huluma fal yastaazinoo kamas taazanal lazeena min qablihim; kazaalika yubaiyinul laahu lakum Aayaatih; wallaahu 'Aleemun Hakeem", english: "But when the children among you come of age, let them (also) ask for permission, as do those senior to them (in age): Thus does Allah make clear His Signs to you: for Allah is full of knowledge and wisdom", romanUrdu: "Aur jab tumhare bacchey aqal ki hadd (sex conscious /puberty) ko pahunch jayein to chahiye ke usi tarah ijazat lekar aaya karein jis tarah unke baday (elders) ijazat lete rahey hain. Is tarah Allah apni aayat tumhare saamne kholta hai, aur woh aleem o hakeem hai" },
    { number: 60, arabic: "وَٱلْقَوَٰعِدُ مِنَ ٱلنِّسَآءِ ٱلَّٰتِى لَا يَرْجُونَ نِكَاحًۭا فَلَيْسَ عَلَيْهِنَّ جُنَاحٌ أَن يَضَعْنَ ثِيَابَهُنَّ غَيْرَ مُتَبَرِّجَٰتٍۭ بِزِينَةٍۢ ۖ وَأَن يَسْتَعْفِفْنَ خَيْرٌۭ لَّهُنَّ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌۭ", transliteration: "WaalqawaAAidu mina alnnisai allatee la yarjoona nikahan falaysa AAalayhinna junahun an yadaAAna thiyabahunna ghayra mutabarrijatin bizeenatin waan yastaAAfifna khayrun lahunna waAllahu sameeAAun AAaleemun", transliterationB: "Walqawaa'idu minan nisaaa'il laatee laa yarjoona nikaahan falisa 'alaihinna junaahun ai yada'na siyaabahunna ghaira mutabar rijaatim bizeenah; wa ai yasta'fifna khairul lahunn; wallaahu Samee'un 'Aleem", english: "Such elderly women as are past the prospect of marriage,- there is no blame on them if they lay aside their (outer) garments, provided they make not a wanton display of their beauty: but it is best for them to be modest: and Allah is One Who sees and knows all things", romanUrdu: "Aur jo auratein jawani se guzri baithi hon, nikah ki umeedwaar na hon, woh agar apni chadarein (outer graments) utaar kar rakh dein to unpar koi gunaah nahin, bashart ke zeenat ki numaish karne wali na hon. Taham (nevertheless) woh bhi haya-daari hi baratein (behave modestly) to unke haqq mein accha hai, aur Allah sab kuch sunta aur jaanta hai" },
    { number: 61, arabic: "لَّيْسَ عَلَى ٱلْأَعْمَىٰ حَرَجٌۭ وَلَا عَلَى ٱلْأَعْرَجِ حَرَجٌۭ وَلَا عَلَى ٱلْمَرِيضِ حَرَجٌۭ وَلَا عَلَىٰٓ أَنفُسِكُمْ أَن تَأْكُلُوا۟ مِنۢ بُيُوتِكُمْ أَوْ بُيُوتِ ءَابَآئِكُمْ أَوْ بُيُوتِ أُمَّهَٰتِكُمْ أَوْ بُيُوتِ إِخْوَٰنِكُمْ أَوْ بُيُوتِ أَخَوَٰتِكُمْ أَوْ بُيُوتِ أَعْمَٰمِكُمْ أَوْ بُيُوتِ عَمَّٰتِكُمْ أَوْ بُيُوتِ أَخْوَٰلِكُمْ أَوْ بُيُوتِ خَٰلَٰتِكُمْ أَوْ مَا مَلَكْتُم مَّفَاتِحَهُۥٓ أَوْ صَدِيقِكُمْ ۚ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَأْكُلُوا۟ جَمِيعًا أَوْ أَشْتَاتًۭا ۚ فَإِذَا دَخَلْتُم بُيُوتًۭا فَسَلِّمُوا۟ عَلَىٰٓ أَنفُسِكُمْ تَحِيَّةًۭ مِّنْ عِندِ ٱللَّهِ مُبَٰرَكَةًۭ طَيِّبَةًۭ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ لَعَلَّكُمْ تَعْقِلُونَ", transliteration: "Laysa AAala alaAAma harajun wala AAala alaAAraji harajun wala AAala almareedi harajun wala AAala anfusikum an takuloo min buyootikum aw buyooti abaikum aw buyooti ommahatikum aw buyooti ikhwanikum aw buyooti akhawatikum aw buyooti aAAmamikum aw buyooti AAammatikum aw buyooti akhwalikum aw buyooti khalatikum aw ma malaktum mafatihahu aw sadeeqikum laysa AAalaykum junahun an takuloo jameeAAan aw ashtatan faitha dakhaltum buyootan fasallimoo AAala anfusikum tahiyyatan min AAindi Allahi mubarakatan tayyibatan kathalika yubayyinu Allahu lakumu alayati laAAallakum taAAqiloona", transliterationB: "Laisa 'alal a'maa barajunw wa laa 'alal a'raji barajunw wa laa 'alal mareedi barajun wa laa 'alaa anfusikum an taakuloo mim buyootikum aw buyooti aabaaa'ikum aw buyooti ummahaatikum aw buyooti ikhwaanikum aw buyooti akhawaatikum aw buyooti a'maamikum aw buyooti 'ammaatikum aw buyooti akhwaalikum aw buyooti khaalaatikum aw maa malaktum mafaatihahooo aw sadeeqikum; laisa 'alaikum junaahun an taakuloo jamee'an aw ashtaata; fa izaa dakhaltum buyootan fasallimoo 'alaaa anfusikum tahiyyatam min 'indil laahi mubaarakatan taiyibah; kazaalika yubai yinul laahu lakumul Aayaati la'allakum ta'qiloon", english: "It is no fault in the blind nor in one born lame, nor in one afflicted with illness, nor in yourselves, that ye should eat in your own houses, or those of your fathers, or your mothers, or your brothers, or your sisters, or your father's brothers or your father's sisters, or your mother's brothers, or your mother's sisters, or in houses of which the keys are in your possession, or in the house of a sincere friend of yours: there is no blame on you, whether ye eat in company or separately. But if ye enter houses, salute each other - a greeting of blessing and purity as from Allah. Thus does Allah make clear the signs to you: that ye may understand", romanUrdu: "Koi haraj nahin agar koi andha, ya langda, ya mareez (kisi ke ghar se kha le) aur na tumhare upar is mein koi muzahiqa (harm/jarj) hai ke apne gharon se khao ya apne baap dada ke gharon se, ya apni maa, nani ke gharon se , ya apne bhaiyon ke gharon se, ya apni behno ke gharon se, ya apne chachaon ke gharon se , ya apni phoopiyon ke gharon se, ya apne mamuon ke gharon se, ya apni khalaon ke gharon se, ya un gharon se jinki kunjiyan (keys) tumhari supurdagi (possession) mein hon, ya apne doston ke gharon se. Is mein bhi koi haraj nahin ke tumlog milkar khao ya alag alag, albatta jab gharon mein dakhil hua karo to apne logon ko salaam kiya karo, dua e khair, Allah ki taraf se muqarrar farmayi hui, badi babarakat aur pakeeza. Is tarah Allah taala tumhare saamne aayat bayaan karta hai, tawaqqu hai ke tum samajh bujh se kaam logey" },
    { number: 62, arabic: "إِنَّمَا ٱلْمُؤْمِنُونَ ٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَإِذَا كَانُوا۟ مَعَهُۥ عَلَىٰٓ أَمْرٍۢ جَامِعٍۢ لَّمْ يَذْهَبُوا۟ حَتَّىٰ يَسْتَـْٔذِنُوهُ ۚ إِنَّ ٱلَّذِينَ يَسْتَـْٔذِنُونَكَ أُو۟لَٰٓئِكَ ٱلَّذِينَ يُؤْمِنُونَ بِٱللَّهِ وَرَسُولِهِۦ ۚ فَإِذَا ٱسْتَـْٔذَنُوكَ لِبَعْضِ شَأْنِهِمْ فَأْذَن لِّمَن شِئْتَ مِنْهُمْ وَٱسْتَغْفِرْ لَهُمُ ٱللَّهَ ۚ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Innama almuminoona allatheena amanoo biAllahi warasoolihi waitha kanoo maAAahu AAala amrin jamiAAin lam yathhaboo hatta yastathinoohu inna allatheena yastathinoonaka olaika allatheena yuminoona biAllahi warasoolihi faitha istathanooka libaAAdi shanihim fathan liman shita minhum waistaghfir lahumu Allaha inna Allaha ghafoorun raheemun", transliterationB: "Innamal mu'minoonal lazeena aamanoo billaahi wa Rasoolihee wa izaa kaanoo ma'ahoo 'alaaa amrin jaami'il lam yazhaboo hataa yastaazinooh; innal lazeena yastaa zinookana ulaaa'ikal lazeena yu'minoona billaahi wa Rasoolih; fa izas taazanooka liba'di shaanihim faazal liman shi'ta minhum wastaghfir lahumul laah; innal laaha Gahfoor Raheem", english: "Only those are believers, who believe in Allah and His Messenger: when they are with him on a matter requiring collective action, they do not depart until they have asked for his leave; those who ask for thy leave are those who believe in Allah and His Messenger; so when they ask for thy leave, for some business of theirs, give leave to those of them whom thou wilt, and ask Allah for their forgiveness: for Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Momin to asal mein wahi hain jo Allah aur uske Rasool ko dilse maane aur jab kisi ijtimaii kaam ke mauqe par Rasool ke saath hon to ussey ijazat liye bagair na jayein, Jo log tumse ijazat maangte hain wahi Allah aur Rasool ke maannay walay hain. Pas jab woh apne kisi kaam se ijazat maangein to jisey tum chaho ijazat de diya karo aur aise logon ke haqq mein Allah se dua e magfirat kiya karo. Allah yaqeenan gafoor o raheem hai" },
    { number: 63, arabic: "لَّا تَجْعَلُوا۟ دُعَآءَ ٱلرَّسُولِ بَيْنَكُمْ كَدُعَآءِ بَعْضِكُم بَعْضًۭا ۚ قَدْ يَعْلَمُ ٱللَّهُ ٱلَّذِينَ يَتَسَلَّلُونَ مِنكُمْ لِوَاذًۭا ۚ فَلْيَحْذَرِ ٱلَّذِينَ يُخَالِفُونَ عَنْ أَمْرِهِۦٓ أَن تُصِيبَهُمْ فِتْنَةٌ أَوْ يُصِيبَهُمْ عَذَابٌ أَلِيمٌ", transliteration: "La tajAAaloo duAAaa alrrasooli baynakum kaduAAai baAAdikum baAAdan qad yaAAlamu Allahu allatheena yatasallaloona minkum liwathan falyahthari allatheena yukhalifoona AAan amrihi an tuseebahum fitnatun aw yuseebahum AAathabun aleemun", transliterationB: "La taj'aloo du'aaa'ar Rasooli bainakum kadu'aaa'i badikum ba'daa; qad ya'lamul laahul lazeena yatasallaloona minkum liwaazaa; fal yahzaril lazeena yukhaalifoona 'an amriheee an tuseebahum fitnatun aw yuseebahum 'azaabun aleem", english: "Deem not the summons of the Messenger among yourselves like the summons of one of you to another: Allah doth know those of you who slip away under shelter of some excuse: then let those beware who withstand the Messenger's order, lest some trial befall them, or a grievous penalty be inflicted on them", romanUrdu: "Musalmano, apne darmiyan Rasool ke bulane ko aapas mein ek dusre ka sa bulana na samajh baitho. Allah un logon ko khoob jaanta hai jo tum mein aisey hain ke ek dusre ki aadd letay huey chupke se satak jatey hain. Rasool ke hukum ki khilaf warzi karne walon ko darna chahiye ke woh kisi fitne mein giraftar na ho jayein, ya unpar dardnaak azaab na aa jaaye" },
    { number: 64, arabic: "أَلَآ إِنَّ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ قَدْ يَعْلَمُ مَآ أَنتُمْ عَلَيْهِ وَيَوْمَ يُرْجَعُونَ إِلَيْهِ فَيُنَبِّئُهُم بِمَا عَمِلُوا۟ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۢ", transliteration: "Ala inna lillahi ma fee alssamawati waalardi qad yaAAlamu ma antum AAalayhi wayawma yurjaAAoona ilayhi fayunabbiohum bima AAamiloo waAllahu bikulli shayin AAaleemun", transliterationB: "Alaaa inna lillaahi maa fis samaawaati wal ardi qad ya'lamu maaa antum 'alaihi wa Yawma yurja'oona ilaihi fa yunaabi 'uhum bimaa 'amiloo; wallaahu bikulli shai'in 'Aleem", english: "Be quite sure that to Allah doth belong whatever is in the heavens and on earth. Well doth He know what ye are intent upon: and one day they will be brought back to Him, and He will tell them the truth of what they did: for Allah doth know all things", romanUrdu: "Khabardaar raho, aasmaan o zameen mein jo kuch hai Allah ka hai. Tum jis rawish par bhi ho Allah usko jaanta hai. Jis roz log uski taraf paltenge woh unhein bata dega ke woh kya kuch karke aaye hain. Woh har cheez ka ilam rakhta hai" }
  ]
};
